  'changzhou/dino': ('حديقة الديناصورات', 'تعتبر أشهر حديقة ترفيهية للديناصورات في الصين، وهي رمز المدينة المفضل للعائلات.'),
  'changzhou/pagoda': ('معبد تياننينغ', 'يرتفع هذا المعبد في وسط المدينة ليصل طوله إلى 153 متراً، مما يجعله أطول معبد في العالم.'),
  'changzhou/comb': ('حرفة الأمشاط', 'كانت أمشاط تشانغتشو المصنوعة يدوياً منذ آلاف السنين تُقدم كهدايا ملكية.'),
  'changzhou/canal': ('القناة الكبرى', 'يستمتع الزوار بالتنزه على ضفاف القناة لاستكشاف الأحياء القديمة ومشاهدة أضواء الليل.'),
  'shaoxing/wine': ('نبيذ شاوشينغ', 'يُصنع هنا نبيذ الأرز الأصفر الشهير المستخدم في المطبخ الصيني منذ آلاف السنين.'),
  'shaoxing/bridge': ('الجسور الحجرية', 'تحتفظ مدينة شاوشينغ، التي تتخللها القنوات المائية، بمئات الجسور الحجرية المقوسة.'),
  'shaoxing/pen': ('مهد الخط العربي الصيني', 'يُعد جناح الأوركيد الخاص بالخطاط الشهير وانغ شي تشي موقعاً مقدساً لفن الخط.'),
  'shaoxing/boat': ('قوارب ووبنغ', 'تُعد قوارب ووبنغ ذات المظلات السوداء، التي تُجدف بالقدم، وسيلة التنقل الكلاسيكية في القنوات المائية.'),
  'bengbu/shell': ('ميناء اللؤلؤ', 'يعني اسم المدينة \'رصيف المحار\'، وقد اشتهرت قديماً بإنتاج لآلئ نهر هواي.'),
  'bengbu/train': ('بوابة السكك الحديدية', 'تعد مدينة بنغبو نقطة عبور رئيسية لخطوط السكك الحديدية بين شمال الصين وجنوبها، وقد ازدهرت المدينة بفضل محطتها المركزية.'),
  'bengbu/river': ('نهر هواي', 'يجري نهر هواي عبر هذه المدينة، وهو النهر الذي يُعتبر تاريخياً الفاصل الطبيعي بين شمال الصين وجنوبها.'),
  'bengbu/blossom': ('مهرجانات الربيع', 'تكتسي المتنزهات المطلة على ضفاف النهر بحلة زاهية خلال مهرجانات الزهور التي تقام في كل ربيع.'),
  'jiujiang/mountain': ('جبل لو', 'ألهمت قمم جبل لو الضبابية، المدرج ضمن قائمة اليونسكو للتراث العالمي، أجيالاً من الشعراء والرسامين الصينيين.'),
  'jiujiang/tea': ('شاي السحاب والضباب', 'يُعد شاي "يون وو" المستخلص من منحدرات جبل لو واحداً من أرقى وأجود أنواع الشاي في الصين.'),
  'jiujiang/lake': ('بحيرة بويانغ', 'تُعد بحيرة بويانغ أكبر بحيرة للمياه العذبة في الصين، وتستقبل آلاف الطيور المهاجرة خلال فصل الشتاء.'),
  'jiujiang/scroll': ('مدينة القصائد', 'خلّد كبار الشعراء مثل باي جويي وسو شي إبداعاتهم الأدبية في هذه المدينة التي تُعد بوابة نهرية تاريخية.'),
  'quanzhou/ship': ('طريق الحرير البحري', 'كانت مدينة تشوانتشو، المعروفة قديماً باسم "زيتون"، أعظم ميناء تجاري في العصور الوسطى وهي مدرجة ضمن قائمة اليونسكو.'),
  'quanzhou/mosque': ('مسجد تشينغجينغ', 'يُعد مسجد تشينغجينغ الحجري، الذي شُيّد عام 1009 ميلادي، واحداً من أقدم المساجد في الصين.'),
  'quanzhou/puppet': ('فن العرائس', 'يُعتبر فن تحريك العرائس بالخيوط في تشوانتشو تقليداً مسرحياً عريقاً يعود تاريخه إلى ألف عام.'),
  'quanzhou/tea': ('شاي تيغوانين', 'يُعرف شاي الأولونغ القادم من منطقة أنشي المجاورة عالمياً باسم شاي "الإلهة الحديدية".'),
  'shanghai/pearl': ('برج لؤلؤة الشرق', 'يُعد هذا البرج، بكراته الوردية الشاهقة المطلة على نهر هوانغبو، الرمز الأبرز لمدينة شنغهاي الحديثة.'),
  'shanghai/bund': ('منطقة البوند', 'تعكس واجهات الفنادق والمباني التاريخية على ضفاف النهر عظمة شنغهاي في الماضي.'),
  'shanghai/garden': ('حديقة يو', 'تُشكل هذه الحديقة الكلاسيكية التي تعود إلى عهد أسرة مينغ واحة هادئة بفضل صخورها وبركها المائية في قلب المدينة.'),
  'shanghai/xlb': ('زلابية الحساء', 'تُعد هذه الفطائر المطهوة على البخار والمحشوة بالمرق الساخن تحفة فنية في مائدة إفطار شنغهاي.'),
  'hangzhou/lake': ('البحيرة الغربية', 'تُعد هذه البحيرة، بما تضمه من أشجار الصفصاف والجزر والجسور المقوسة، الأكثر إشادة في الشعر الصيني.'),
  'hangzhou/tea': ('شاي لونغجينغ', 'يُزرع شاي "بئر التنين" الأخضر على المنحدرات المحيطة بالبحيرة، ويُعتبر أشهر أنواع الشاي في الصين.'),
  'hangzhou/temple': ('معبد لينغين', 'يشتهر هذا المعبد الذي يعود تاريخه إلى 1700 عام، والمعروف بـ "معبد ملاذ الروح"، بنقوشه الصخرية وتمثال بوذا العملاق.'),
  'hangzhou/silk': ('مدينة الحرير', 'يُنسج حرير هانغتشو منذ ألف عام، وهو الذي شكّل ثراء الطرف الشرقي لطريق الحرير.'),
  'chongqing/hongya': ('كهف هونغيا', 'مجمع من المنازل المبنية على ركائز متينة فوق المنحدر الصخري، يتلألأ ليلاً فوق النهر كأنه مشهد من القصص الخيالية.'),
  'chongqing/hotpot': ('قدر تشونغتشينغ الساخن', 'يُعد القدر الساخن، الذي يغلي بالزيت الحار والفلفل المخدر، الروح النارية لهذه المدينة الجبلية.'),
  'chongqing/monorail': ('قطار تشونغتشينغ المعلق', 'يُعتبر القطار الخفيف الذي يخترق المباني السكنية المشهد الأبرز لهذه المدينة المبنية على التلال.'),
  'chongqing/river': ('مضايق اليانغتسي', 'تنطلق رحلات السفن السياحية عبر المضايق الثلاثة من هذا الميناء، حيث تنهض المدينة عند ملتقى نهرين.'),
  'dalian/square': ('ساحة شينغهاي', 'تُعد أكبر ساحة مدينة في آسيا، وتنبض بالحياة خلال المهرجانات والعروض المقامة على طول الواجهة البحرية.'),
  'dalian/beach': ('شواطئ داليان', 'بفضل خلجانها الصخرية وصيفها المعتدل، تُعتبر داليان المنتجع الساحلي المفضل في شمال الصين.'),
  'dalian/football': ('مدينة كرة القدم', 'تُلقب بـ "مهد كرة القدم" في الصين، حيث نشأت هنا أكثر الأندية تتويجاً بالألقاب في البلاد.'),
  'dalian/seafood': ('مأكولات داليان البحرية', 'تتزين موائد المدينة بأشهى المأكولات البحرية من مياه البحر الأصفر الباردة، مثل الإسقلوب والروبيان وقنفذ البحر.'),
  'shenyang/palace': ('قصر موكدين', 'هو القصر الأول لسلالة تشينغ، ويُعتبر بمثابة الشقيق الأصغر للمدينة المحرمة في بكين.'),
  'shenyang/tomb': ('مقابر تشينغ', 'تُعد المقابر الشرقية والشمالية التي تحيط بالمدينة أضرحة أثرية لمؤسسي سلالة تشينغ.'),
  'shenyang/factory': ('مهد الصناعة', 'وُلدت الصناعات الثقيلة الصينية هنا، وقد أكسبتها مصانعها الضخمة لقب "رور الشرق".'),
  'shenyang/dumpling': ('زلابية لاوبيان', 'تُعد زلابية لاوبيان المطهوة على البخار، والتي يعود تاريخها إلى مئتي عام، الطبق المميز على المائدة الشمالية.'),
  'hefei/judge': ('ضريح القاضي باو', 'وُلد القاضي العادل باو تشنغ في هذه المدينة، ويُعتبر ضريحه رمزاً للنزاهة والاستقامة.'),
  'hefei/science': ('مدينة العلوم', 'مركز تقني يضم نخبة من الجامعات والمختبرات الرائدة في الصين.'),
  'hefei/lake': ('بحيرة تشاوهو', 'إحدى أكبر خمس بحيرات للمياه العذبة في الصين، وتشتهر بأسماكها البيضاء وسرطانات البحر.'),
  'hefei/cake': ('كعكة السمسم لو', 'تُعد كعكة السمسم المحشوة بالحلوى من أقدم الحلويات التقليدية في مدينة لوتشو العريقة.'),
  'foshan/wingchun': ('وينغ تشون', 'تُعد المدينة موطن فن الوينغ تشون القتالي، حيث تعود إليها جذور المعلم ييب مان وبروس لي.'),
  'foshan/lion': ('رقصة الأسد', 'تُعتبر المدينة عاصمة رقصة الأسد الجنوبية، حيث تقفز الأسود الملونة ببراعة فوق الأعمدة خلال المهرجانات.'),
  'foshan/ceramic': ('فخار شيوان', 'لا تزال أفران الفخار التي يعود تاريخها إلى ألف عام تنتج تماثيل شيوان الحيوية.'),
  'foshan/opera': ('أوبرا كانتونية', 'نشأ هذا الفن المسرحي الأكثر شعبية في جنوب الصين وتطور على هذه الأراضي.'),
  'guiyang/pavilion': ('جناح جياشيو', 'يُعد هذا الجناح المكون من ثلاث طبقات والمطل على نهر نانمينغ رمزاً للمدينة منذ أربعمئة عام.'),
  'guiyang/sourfish': ('حساء السمك الحامض', 'يُعتبر السمك المطهو في مرق الطماطم المخمرة الحامض الطبق المميز لمقاطعة قويتشو.'),
  'guiyang/waterfall': ('شلالات هوانغغوشو', 'تتدفق مياه أحد أكبر الشلالات في آسيا بقوة، مما يخلق أقواس قزح مذهلة.'),
  'guiyang/miao': ('ثقافة مياو', 'تضفي مهرجانات وتطريزات شعب المياو، الذين يرتدون التيجان الفضية، بهجةً على القرى الجبلية.'),
  'changchun/film': ('مدينة السينما', 'تضم المدينة الاستوديوهات التي وُلدت فيها السينما الصينية، وتُلقب بـ "هوليوود الشرق".'),
  'changchun/car': ('مدينة السيارات', 'خرجت أول سيارة صينية الصنع من مصانع هذه المدينة، التي تُعد العاصمة الوطنية لصناعة السيارات.'),
  'changchun/palace': ('قصر الإمبراطور الأخير', 'يعد هذا القصر الذي عاش فيه آخر أباطرة الصين شاهداً صامتاً على حقبة تاريخية مضطربة.'),
  'changchun/snow': ('ثلوج الشتاء', 'تتألق المدينة خلال فصول الشتاء الطويلة بمنحوتاتها الجليدية ومسارات التزلج البيضاء.'),
  'xining/lake': ('بحيرة تشينغهاي', 'تُعرف أكبر بحيرة مالحة في الصين بحقول زهور اللفت الصفراء التي تحيط بها في فصل الصيف.'),
  'xining/monastery': ('دير كومبوم', 'يُعد أحد الأديرة الستة الكبرى للبوذية التبتية، ويشتهر بمنحوتاته المصنوعة من زبدة الياك.'),
  'xining/flower': ('زهور اللفت', 'تكتسي الهضبة في شهر يوليو بحقول ذهبية من زهور اللفت تمتد حتى الأفق.'),
  'xining/lamb': ('لحم الياك والضأن', 'تتميز نكهات الهضبة بأطباق المعكرونة المسحوبة يدوياً وأسياخ لحم الضأن التي تشتهر بها مطابخ قوميتي هوي والتبت.'),
  'guilin/karst': ('تضاريس كارست نهر لي', 'تعد القمم الكلسية التي ترتفع وسط الضباب المشهد المطبوع على ورقة العشرين يوان النقدية.'),
  'guilin/elephant': ('تلة جذع الفيل', 'تعتبر الصخرة التي تتخذ شكل فيل يغمس خرطومه في النهر الرمز المحبوب للمدينة.'),
  'guilin/terrace': ('مصاطب لونغجي للأرز', 'تُشكل مصاطب "عمود الفقري للتنين" التي تلتف حول المنحدرات سلماً يعكس قروناً من الكدح.'),
  'guilin/osmanthus': ('أزهار الأوسمانثوس', 'يعني اسم المدينة "غابة الأوسمانثوس"، حيث تغرق المدينة في الخريف برائحة أزهارها العطرة.'),
  'wenzhou/merchant': ('روح التجارة', 'يُعرف رواد الأعمال في ونتشو ببراعتهم التجارية، حيث أسسوا شبكات أعمال تمتد عبر أرجاء العالم.'),
  'wenzhou/shoe': ('الأحذية والجلود', 'تنتج هذه المدينة الصناعية حصة ضخمة من الأحذية الجلدية في العالم.'),
  'wenzhou/mountain': ('جبال ياندانغ', 'تُعرف هذه الجبال بشلالاتها وقممها المسننة، وتُلقب بـ "الجبل الأول على البحر".'),
  'wenzhou/seafood': ('المأكولات البحرية', 'تعتمد المائدة المحلية في ونتشو بشكل أساسي على الحبار والمحار والأسماك المستخرجة من بحر الصين الشرقي.'),
  'tangshan/memorial': ('نصب تذكاري لزلزال تانغشان', 'يعد الحديقة التذكارية لزلزال عام 1976 الكبير رمزاً لمدينة ولدت من جديد.'),
  'tangshan/coal': ('منجم الفحم والصلب', 'شهدت هذه المدينة افتتاح أول منجم فحم وسكة حديدية حديثة في الصين، مما جعلها مهد الصناعة الوطنية.'),
  'tangshan/ceramic': ('خزف تانغشان', 'تُعرف المدينة بلقب "مدينة الخزف في الشمال"، حيث يزين صيني العظام الفاخر الموائد بأناقته الفريدة.'),
  'tangshan/lake': ('حديقة نانهو', 'تحولت حفرة منجم قديمة إلى حديقة بحيرة خلابة أصبحت بمثابة الرئة الخضراء للمدينة.'),
  'anshan/steel': ('مدينة الصلب', 'تأسست هنا أكبر مصانع الصلب في الصين، مما منح المدينة لقب "عاصمة الصلب" في البلاد.'),
  'anshan/jade': ('يشم شيويان', 'تضم المدينة أكبر منحوتة يشم في العالم، وتُعد موطن اليشم في الصين.'),
  'anshan/mountain': ('جبل تشيان', 'يُعرف الجبل بـ "قمم اللوتس الألف"، وهو قمة مقدسة في الشمال تشتهر بمعابدها وتضاريسها الصخرية.'),
  'anshan/spring': ('ينابيع تانغغانغزي', 'ينابيع حارة يقصدها الناس للاستشفاء منذ ألف عام، وقد كانت وجهة مفضلة للأباطرة قديماً.'),
  'linyi/market': ('سوق الجملة', 'يُعد أكبر مركز لتجارة الجملة في شمال الصين، حيث تُشحن البضائع منه إلى جميع أنحاء البلاد.'),
  'linyi/brush': ('سيد الخط العربي', 'وُلد هنا "حكيم الخط" الصيني وانغ شي تشي، وتُعرف المدينة بكونها أرض الحبر والفنون.'),
  'linyi/mountain': ('جبل منغ', 'يُعد ثاني أعلى جبل في مقاطعة شاندونغ، وهو بمثابة منتجع طبيعي غني بالهواء النقي والشلالات.'),
  'linyi/pancake': ('فطائر ييمينغ', 'تُعتبر فطائر الذرة الرقيقة "جيان بينغ" الغذاء الأساسي التقليدي لسكان جبال ييمينغ منذ القدم.'),
  'cangzhou/lion': ('الأسد الحديدي', 'يُعد تمثال الأسد الحديدي الضخم الذي يعود تاريخه إلى 1100 عام رمزاً للفخر في المدينة.'),
  'cangzhou/martial': ('الفنون القتالية', 'تُلقب المدينة بـ "موطن الووشو" في الصين، حيث خرج منها أشهر الأساتذة ومدارس القتال.'),
  'cangzhou/canal': ('القناة الكبرى', 'تمر القناة الكبرى الرابطة بين بكين وهانغتشو عبر المدينة، ولا تزال أرصفتها القديمة قائمة حتى اليوم.'),
  'cangzhou/jujube': ('العناب الذهبي', 'يُعتبر العناب ذو القشرة الرقيقة والمذاق الحلو، المعروف بـ "الخيط الذهبي"، ملك الفواكه المجففة.'),
  'nantong/textile': ('مدينة المنسوجات', 'تُعد نانتونغ عاصمة المنسوجات المنزلية في الصين، حيث تصل أقمشتها القطنية إلى الأسواق في جميع أنحاء العالم.'),
  'nantong/mountain': ('جبل لانغ', 'يرتفع هذا الجبل المقدس ذو القمم الخمس عند مصب نهر يانغتسي، ويُعد وجهة شهيرة للحج والاستمتاع بالمناظر الطبيعية.'),
  'nantong/kite': ('طائرات بانيو الورقية', 'تُعتبر طائرات "بانيو" الورقية المزودة بصفارات طنين حرفة تقليدية عريقة تشتهر بها المدينة.'),
  'nantong/school': ('رائد التعليم', 'أسس الصناعي تشانغ جيان هنا أول مدرسة ومتحف حديث في الصين.'),
  'taizhou/opera': ('مي لان فانغ', 'تُعد هذه المدينة مسقط رأس مي لان فانغ، الأستاذ الأسطوري لأوبرا بكين.'),
  'taizhou/tea': ('شاي الصباح', 'يُعتبر طقس "تساوتشا" الصباحي، الذي يجمع بين تناول الكعك المطهو على البخار وشرب الشاي، تقليداً أصيلاً في المدينة.'),
  'taizhou/boat': ('مهرجان قينتونغ للقوارب', 'في فصل الربيع، ينبض النهر بالحياة خلال مهرجان يضم مئات المجدفين في سباقات حماسية.'),
  'taizhou/meatball': ('كرات لحم رأس الأسد', 'تُعد كرات لحم الخنزير الكبيرة والطرية المعروفة باسم "رأس الأسد" طبقاً كلاسيكياً من مطبخ هوايانغ.'),
  'jinhua/ham': ('لحم جينهوا المقدد', 'يُعد هذا اللحم الأحمر، الذي يُعالج بطريقة تعود لقرون مضت، الأشهر من نوعه في الصين.'),
  'jinhua/film': ('استوديوهات هنغديان', 'تُعد أكبر موقع تصوير خارجي في العالم، حيث يتم تصوير عدد لا يحصى من المسلسلات التاريخية فيها.'),
  'jinhua/cave': ('كهف شوانغلونغ', 'يأخذك هذا الكهف الجوفي، الذي تدخله بالقارب عبر بوابة صخرية منخفضة، في رحلة تحبس الأنفاس.'),
  'jinhua/bridge': ('الجسور القديمة', 'تجسد الجسور الحجرية المقوسة والبلدات المائية سحر منطقة جيانغنان وجمالها.'),
  'wuhu/park': ('فانغتي وندرلاند', 'تُعد واحدة من أكبر مدن الملاهي في الصين، وتوفر للعائلات أياماً مليئة بالإثارة والمرح.'),
  'wuhu/ironart': ('الرسم بالحديد', 'تُعد لوحات "الرسم بالحديد" الأنيقة، التي تُصاغ من الحديد المطاوع، حرفة يدوية يعود تاريخها إلى 300 عام.'),
  'wuhu/rice': ('ميناء الأرز', 'كانت هذه المدينة الواقعة على ضفاف نهر يانغتسي تاريخياً أكبر سوق للأرز في الصين.'),
  'wuhu/river': ('ميناء يانغتسي', 'يُعد هذا الميناء النهري النشط البوابة البحرية الرئيسية لمقاطعة آنهوي.'),
  'huangshan/peak': ('الجبل الأصفر', 'يُعتبر أشهر جبل في الصين بفضل قمم الجرانيت وبحر السحب وأشجار الصنوبر الملتوية.'),
  'huangshan/village': ('قرية هونغ تسون', 'تتميز قرى هوي بجدرانها البيضاء ومجاريها المائية المدرجة ضمن قائمة اليونسكو، وتبدو وكأنها لوحة فنية.'),
  'huangshan/tea': ('شاي ماوفنغ', 'يُقطف هذا الشاي الأخضر ذو البراعم الزغبية من المنحدرات الضبابية، ويُصنف ضمن أشهر عشرة أنواع من الشاي في الصين.'),
  'huangshan/ink': ('حبر وفنون هويتشو', 'يُعد حبر هوي والمنازل الخشبية المنحوتة وفن الخط من الكنوز الثقافية لهذه المنطقة.'),
  'yichun/moon': ('جبل مينغيو', 'يشتهر جبل "القمر الساطع" بينابيعه الحارة وإطلالاته البانورامية عبر التلفريك.'),
  'yichun/spring': ('الينابيع الحارة', 'جعلت الينابيع الحارة النادرة والغنية بالسيلينيوم من المدينة مركزاً للاستشفاء في الصين.'),
  'yichun/zen': ('بوذية تشان', 'تدعو المعابد الجبلية المتجذرة في طوائف تشان الصينية الزوار إلى التأمل والسكينة.'),
  'yichun/rice': ('سهل الأرز', 'لطالما كان سهل يوان-هي الخصب بمثابة مخزن الحبوب لمقاطعة جيانغشي.'),
  'zhangzhou/narcissus': ('زهرة النرجس', 'تنمو هنا أشهر أبصال النرجس في الصين، والتي تُعد رمزاً لمهرجانات الربيع.'),
  'zhangzhou/tulou': ('بيوت التولو', 'هي حصون دائرية ضخمة مبنية من التربة المدكوكة ومدرجة ضمن قائمة اليونسكو، وتجمع القرية بأكملها تحت سقف واحد.'),
  'zhangzhou/banana': ('الفواكه الاستوائية', 'تحافظ بساتين الموز واللونغان واليوسفي على اخضرار الدلتا الدافئة طوال العام.'),
  'zhangzhou/coast': ('جزيرة دونغشان', 'تُعد الجزيرة لؤلؤة الساحل الجنوبي بفضل شواطئها الذهبية وقراها التي يعمل سكانها في صيد الأسماك.'),
  'beijing/great-wall': ('سور الصين العظيم', 'أطول تحصين في العالم، يمتد لأكثر من 20 ألف كيلومتر لحماية الحدود الشمالية، ويُعد قسم بادالينغ بالقرب من بكين الأكثر زيارة بفضل درجاته الحجرية وأبراج مراقبته.'),
  'beijing/temple': ('معبد السماء', 'مجمع مقدس كان أباطرة أسرتي مينغ وتشينغ يصلون فيه سنوياً من أجل حصاد وفير، ويشتهر بسقفه الأزرق الدائري المكون من ثلاث طبقات والذي بُني دون استخدام مسمار واحد.'),
  'beijing/pagoda': ('معبد تياننينغ', 'يُعد هذا المعبد المبني من الطوب، والذي يبلغ ارتفاعه 57 متراً ويعود إلى عهد أسرة لياو، أحد أقدم الهياكل القائمة في بكين وشاهداً على تاريخها الممتد لألف عام بفضل نقوشه البارزة وتصميمه المثمن.'),
  'beijing/opera': ('أوبرا بكين', 'فن مسرحي صيني تقليدي يمتد لمئتي عام، يدمج بين الغناء والحوار والفنون القتالية والألعاب البهلوانية، حيث تكشف وجوه الممثلين الملونة عن سمات شخصياتهم؛ فاللون الأحمر يرمز للولاء، بينما يرمز الأبيض للمكر.'),
};
